//
//     final package = packageFromJson(jsonString);

import 'dart:convert';

Package packageFromJson(String str) => Package.fromJson(json.decode(str));

String packageToJson(Package data) => json.encode(data.toJson());

class Package {
    String name;
    String version;
    String description;
    String repository;
    String license;
    List<Contributor> contributors;
    String main;
    String types;
    List<String> files;
    Scripts scripts;
    DevDependencies devDependencies;

    Package({
        required this.name,
        required this.version,
        required this.description,
        required this.repository,
        required this.license,
        required this.contributors,
        required this.main,
        required this.types,
        required this.files,
        required this.scripts,
        required this.devDependencies,
    });

    factory Package.fromJson(Map<String, dynamic> json) => Package(
        name: json["name"],
        version: json["version"],
        description: json["description"],
        repository: json["repository"],
        license: json["license"],
        contributors: List<Contributor>.from(json["contributors"].map((x) => Contributor.fromJson(x))),
        main: json["main"],
        types: json["types"],
        files: List<String>.from(json["files"].map((x) => x)),
        scripts: Scripts.fromJson(json["scripts"]),
        devDependencies: DevDependencies.fromJson(json["devDependencies"]),
    );

    Map<String, dynamic> toJson() => {
        "name": name,
        "version": version,
        "description": description,
        "repository": repository,
        "license": license,
        "contributors": List<dynamic>.from(contributors.map((x) => x.toJson())),
        "main": main,
        "types": types,
        "files": List<dynamic>.from(files.map((x) => x)),
        "scripts": scripts.toJson(),
        "devDependencies": devDependencies.toJson(),
    };
}

class Contributor {
    String name;
    String email;

    Contributor({
        required this.name,
        required this.email,
    });

    factory Contributor.fromJson(Map<String, dynamic> json) => Contributor(
        name: json["name"],
        email: json["email"],
    );

    Map<String, dynamic> toJson() => {
        "name": name,
        "email": email,
    };
}

class DevDependencies {
    String nuxtjsEslintConfig;
    String eslint;
    String tap;
    String standardVersion;

    DevDependencies({
        required this.nuxtjsEslintConfig,
        required this.eslint,
        required this.tap,
        required this.standardVersion,
    });

    factory DevDependencies.fromJson(Map<String, dynamic> json) => DevDependencies(
        nuxtjsEslintConfig: json["@nuxtjs/eslint-config"],
        eslint: json["eslint"],
        tap: json["tap"],
        standardVersion: json["standard-version"],
    );

    Map<String, dynamic> toJson() => {
        "@nuxtjs/eslint-config": nuxtjsEslintConfig,
        "eslint": eslint,
        "tap": tap,
        "standard-version": standardVersion,
    };
}

class Scripts {
    String lint;
    String release;
    String testMatrix;
    String test;

    Scripts({
        required this.lint,
        required this.release,
        required this.testMatrix,
        required this.test,
    });

    factory Scripts.fromJson(Map<String, dynamic> json) => Scripts(
        lint: json["lint"],
        release: json["release"],
        testMatrix: json["test:matrix"],
        test: json["test"],
    );

    Map<String, dynamic> toJson() => {
        "lint": lint,
        "release": release,
        "test:matrix": testMatrix,
        "test": test,
    };
}
